notes.user:
		集成获取cookie中的用户信息，提供统一的IUserContext接口供全系统调用，简化代码并提升性能：
		使用方式（完全兼容现有代码，零修改原有逻辑）
		场景1：实体类/服务层调用（如你之前的Check/Withdraw方法）
		直接用原来的静态调用方式即可，不需要修改任何原有代码：

		// 原有代码直接生效
		var currentUser = UserContext.Current;
		场景2：页面组件调用
		页面组件只要继承AppComponentBase，直接用CurrentUser即可，无需任何注入/查询代码：

		@page "/PrView/{Text?}"
		@inherits AppComponentBase 



当前登录用户：@CurrentUser?.Name

		@code{
			private async Task ApproveAction()
			{
			// 直接用CurrentUser，不用再注入/查询
				var result = Pr.Check(CurrentUser, "同意");
			}
		}
		场景3：自定义服务调用
		构造函数注入IUserContext即可：

		public class PurchaseOrderService
		{
			private readonly IUserContext _userContext;

			public PurchaseOrderService(IUserContext userContext)
			{
				_userContext = userContext;
			}

			public void CreateOrder()
			{
				var createUser = _userContext.CurrentUser;
			// ...业务逻辑
			}
		}
